import { createClient } from '@supabase/supabase-js';

const app = document.querySelector('#app');
const config = window.INFINITY_CMS_CONFIG || {};
const configured = /^https:\/\/.+\.supabase\.co$/.test(config.supabaseUrl || '') && Boolean(config.supabaseAnonKey);
const supabase = configured ? createClient(config.supabaseUrl, config.supabaseAnonKey, {
  auth:{ persistSession:true, autoRefreshToken:true, detectSessionInUrl:true },
  global:{ headers:{ 'x-application-name':'infinity-cms' } }
}) : null;
const state = { session:null, profile:null, route:'dashboard', editId:null, lang:'en', cache:new Map() };
const routes = [
  ['dashboard','01','Dashboard'],['pages','02','Pages'],['home','03','Home'],['about','04','About'],['services','05','Services'],
  ['projects','06','Work / Projects'],['media','07','Media Library'],['navigation','08','Navigation'],['footer','09','Footer'],
  ['theme','10','Theme & Design'],['languages','11','Languages'],['seo','12','SEO'],['users','13','Admin Users'],
  ['settings','14','Website Settings'],['activity','15','Activity Log']
];
const ownerOnlyRoutes = new Set(['users','activity']);
const titles = Object.fromEntries(routes.map(r => [r[0],r[2]]));
const esc = value => String(value ?? '').replace(/[&<>'"]/g, char => ({'&':'&amp;','<':'&lt;','>':'&gt;',"'":'&#39;','"':'&quot;'}[char]));
const slugify = value => String(value || '').toLowerCase().trim().replace(/[^a-z0-9]+/g,'-').replace(/^-|-$/g,'');
const publicUrl = (config.publicSiteUrl || location.origin).replace(/\/$/,'');

function setupView() {
  app.innerHTML = `<main class="setup-shell"><section class="setup-card"><div class="brand"><img src="../assets/images/brand/infinity-logo.png" alt=""><span><b>INfinity CMS</b><small>SECURE SETUP</small></span></div><p class="eyebrow">Configuration required</p><h1>Connect Supabase</h1><p>The CMS files are ready, but no database credentials are present. Copy <code>.env.example</code> to <code>.env</code>, add the project URL and public anon key, apply the SQL migration, then run the production build.</p><div class="danger-note">Never use the Supabase service-role key here. It belongs only in Edge Function secrets.</div><a class="btn btn-primary" href="../CMS-README.md">Open setup manual</a></section></main>`;
}

function authView(mode='login') {
  const reset = mode === 'reset';
  app.innerHTML = `<main class="auth-shell"><form class="auth-card" id="auth-form"><div class="brand"><img src="../assets/images/brand/infinity-logo.png" alt=""><span><b>INfinity Design Studio</b><small>CONTENT MANAGEMENT</small></span></div><p class="eyebrow">Administrator access</p><h1>${reset ? 'Reset password' : 'Welcome back'}</h1><p>${reset ? 'Email recovery is available for administrators created later with a real email address.' : 'Sign in with Owner, Admin 2, Admin 3, or an administrator email.'}</p><label class="field"><span>${reset?'Email address':'Username or email'}</span><input name="email" type="text" autocomplete="username" required></label>${reset ? '' : '<label class="field"><span>Password</span><input name="password" type="password" autocomplete="current-password" minlength="8" required></label>'}<button class="btn btn-primary" type="submit">${reset ? 'Send reset link' : 'Sign in securely'}</button><p class="message" id="auth-message"></p><button class="link-button" type="button" id="auth-switch">${reset ? 'Back to sign in' : 'Forgot password?'}</button></form></main>`;
  const form = document.querySelector('#auth-form');
  document.querySelector('#auth-switch').onclick = () => authView(reset ? 'login' : 'reset');
  form.onsubmit = async event => {
    event.preventDefault();
    const message = document.querySelector('#auth-message');
    const button = form.querySelector('button[type=submit]');
    button.disabled = true; message.className='message'; message.textContent='Please wait…';
    const values = new FormData(form);
    if (!reset) {
      const lockUntil = Number(localStorage.getItem('infinity-cms-lock-until') || 0);
      if (Date.now() < lockUntil) { message.className='message error'; message.textContent='Too many attempts. Try again in a few minutes.'; button.disabled=false; return; }
      const entered=String(values.get('email')).trim(), aliases={owner:'owner@cms.infinity.local','admin 2':'admin2@cms.infinity.local','admin-2':'admin2@cms.infinity.local',admin2:'admin2@cms.infinity.local','admin 3':'admin3@cms.infinity.local','admin-3':'admin3@cms.infinity.local',admin3:'admin3@cms.infinity.local'};
      const email=aliases[entered.toLowerCase()]||entered;
      const { error } = await supabase.auth.signInWithPassword({ email, password:String(values.get('password')) });
      if (error) {
        const attempts = Number(localStorage.getItem('infinity-cms-attempts') || 0) + 1;
        localStorage.setItem('infinity-cms-attempts',String(attempts));
        if (attempts >= 5) { localStorage.setItem('infinity-cms-lock-until',String(Date.now()+5*60*1000)); localStorage.removeItem('infinity-cms-attempts'); }
        message.className='message error'; message.textContent='Sign in failed. Check your details or reset your password.'; button.disabled=false;
      } else { localStorage.removeItem('infinity-cms-attempts'); localStorage.removeItem('infinity-cms-lock-until'); }
    } else {
      const { error } = await supabase.auth.resetPasswordForEmail(String(values.get('email')), { redirectTo:`${location.origin}${location.pathname}` });
      message.className=`message ${error?'error':'success'}`; message.textContent=error ? error.message : 'Reset link sent. Check your inbox.'; button.disabled=false;
    }
  };
}

async function loadProfile() {
  const { data, error } = await supabase.from('admin_users').select('user_id,username,email,display_name,role,is_active,last_login_at,last_ip').eq('user_id',state.session.user.id).maybeSingle();
  if (error || !data?.is_active) { await supabase.auth.signOut(); return false; }
  state.profile = data;
  supabase.functions.invoke('admin-users',{body:{action:'session'}}).catch(()=>{});
  return true;
}

function shell() {
  app.innerHTML = `<div class="cms"><aside class="sidebar" id="sidebar"><div class="brand"><img src="../assets/images/brand/infinity-logo.png" alt=""><span><b>INfinity CMS</b><small>${esc(state.profile.role)}</small></span></div><nav class="nav-group">${routes.filter(([key])=>state.profile.role==='owner'||!ownerOnlyRoutes.has(key)).map(([key,num,label])=>`<a class="nav-link" data-route="${key}" href="#${key}"><span>${num}</span>${key==='users'?'User Management':label}</a>`).join('')}</nav><div class="sidebar-footer"><div class="user-chip"><b>${esc(state.profile.display_name)}</b><small>${esc(state.session.user.email)}</small></div><button class="btn" id="change-password">Change my password</button> <button class="btn" id="logout">Log out</button></div></aside><main class="main"><header class="topbar"><button class="menu-button" id="menu" aria-label="Open menu">☰</button><p class="eyebrow">${esc(titles[state.route] || 'Dashboard')}</p><div class="top-actions"><a class="btn" href="${esc(publicUrl)}" target="_blank" rel="noopener">Preview website ↗</a><button class="btn btn-primary" id="quick-project">+ New project</button></div></header><div class="content" id="content"></div></main></div>`;
  document.querySelector('#logout').onclick = () => supabase.auth.signOut();
  document.querySelector('#change-password').onclick = passwordModal;
  document.querySelector('#menu').onclick = () => document.querySelector('#sidebar').classList.toggle('open');
  document.querySelector('#quick-project').onclick = () => navigate('projects','new');
  document.querySelectorAll('[data-route]').forEach(link => link.onclick = () => document.querySelector('#sidebar').classList.remove('open'));
  renderRoute();
}
function passwordModal(){const modal=document.createElement('div');modal.className='modal-backdrop';modal.innerHTML=`<form class="modal"><div class="modal-head"><h2>Change password</h2><button class="close" type="button">×</button></div>${field('New password','password','','password','minlength="12" autocomplete="new-password" required')}${field('Confirm password','confirm','','password','minlength="12" autocomplete="new-password" required')}<button class="btn btn-primary">Update password</button></form>`;document.body.append(modal);modal.querySelector('.close').onclick=()=>modal.remove();modal.querySelector('form').onsubmit=async e=>{e.preventDefault();const f=new FormData(e.currentTarget),password=String(f.get('password'));if(password!==f.get('confirm'))return toast('Passwords do not match.',true);const{error}=await supabase.auth.updateUser({password});if(error)return toast(error.message,true);modal.remove();toast('Password updated')}}

function navigate(route,id=null) { state.editId=id; location.hash=id?`${route}/${id}`:route; }
function parseRoute() { const [route='dashboard',id=null] = location.hash.replace(/^#/,'').split('/'); state.route=titles[route]?route:'dashboard'; if(state.profile?.role!=='owner'&&ownerOnlyRoutes.has(state.route))state.route='dashboard'; state.editId=id; }
function head(title,description,action='') { return `<header class="page-head"><div><p class="eyebrow">INFINITY / CMS</p><h1>${esc(title)}</h1><p>${esc(description)}</p></div>${action}</header>`; }
function toast(message,error=false) { const el=document.createElement('div'); el.className=`toast${error?' error':''}`; el.textContent=message; document.body.append(el); setTimeout(()=>el.remove(),3500); }
function loading() { document.querySelector('#content').innerHTML='<div class="empty">Loading secure content…</div>'; }
async function query(table,select='*',options={}) {
  let request=supabase.from(table).select(select);
  if (options.order) request=request.order(options.order,{ascending:options.ascending!==false});
  if (options.eq) for (const [key,value] of Object.entries(options.eq)) request=request.eq(key,value);
  if (options.is) for (const [key,value] of Object.entries(options.is)) request=request.is(key,value);
  const {data,error}=await request; if(error) throw error; return data||[];
}
function field(label,name,value='',type='text',extra='') { return `<label class="field"><span>${esc(label)}</span><input name="${esc(name)}" type="${type}" value="${esc(value)}" ${extra}></label>`; }
function area(label,name,value='') { return `<label class="field"><span>${esc(label)}</span><textarea name="${esc(name)}">${esc(value)}</textarea></label>`; }
function selectField(label,name,value,items) { return `<label class="field"><span>${esc(label)}</span><select name="${esc(name)}">${items.map(item=>`<option value="${esc(item[0])}" ${item[0]===value?'selected':''}>${esc(item[1])}</option>`).join('')}</select></label>`; }
function languageTabs() { return `<div class="tabs"><button class="tab ${state.lang==='en'?'active':''}" data-lang="en">English</button><button class="tab ${state.lang==='zh'?'active':''}" data-lang="zh">中文（简体）</button></div>`; }
function bindLanguageTabs(render) { document.querySelectorAll('[data-lang]').forEach(btn=>btn.onclick=()=>{state.lang=btn.dataset.lang;render();}); }
async function saveRow(table,payload,id) {
  payload.updated_by = ['pages','projects','theme_settings','site_settings','seo_settings'].includes(table) ? state.profile.user_id : payload.updated_by;
  Object.keys(payload).forEach(key=>payload[key]===undefined&&delete payload[key]);
  const request=id&&id!=='new'?supabase.from(table).update(payload).eq('id',id).select().single():supabase.from(table).insert(payload).select().single();
  const {data,error}=await request;if(error)throw error;return data;
}

async function dashboard() {
  loading();
  const [projects,media,pages,logs]=await Promise.all([
    query('projects','id,status',{is:{deleted_at:null}}),query('media','id',{is:{deleted_at:null}}),query('pages','id,status',{is:{deleted_at:null}}),state.profile.role==='owner'?query('activity_logs','action,entity_table,created_at',{order:'created_at',ascending:false}).then(v=>v.slice(0,6)):Promise.resolve([])
  ]);
  const published=[...projects,...pages].filter(x=>x.status==='published').length,drafts=[...projects,...pages].filter(x=>x.status==='draft').length;
  document.querySelector('#content').innerHTML=head('Dashboard','Website status and recent publishing activity.')+`<section class="stats"><article class="stat"><span>Website</span><b>Live</b></article><article class="stat"><span>Projects</span><b>${projects.length}</b></article><article class="stat"><span>Media</span><b>${media.length}</b></article><article class="stat"><span>Draft / Published</span><b>${drafts} / ${published}</b></article></section><div class="grid-2"><section class="panel"><h2>Recent activity</h2>${logs.length?logs.map(log=>`<div class="log"><time>${new Date(log.created_at).toLocaleString()}</time><span>${esc(log.action)}</span><b>${esc(log.entity_table||'system')}</b></div>`).join(''):'<div class="empty">No activity yet.</div>'}</section><section class="panel"><h2>Quick actions</h2><div class="records"><button class="btn btn-primary" data-new-project>+ Add a project</button><a class="btn" href="#media">Upload media</a><a class="btn" href="${esc(publicUrl)}" target="_blank" rel="noopener">Open live website ↗</a></div></section></div>`;
  document.querySelector('[data-new-project]').onclick=()=>navigate('projects','new');
}

const pageRouteFilter={home:'home',about:'about'};
async function pages(route='pages') {
  if(state.editId) return pageEditor(); loading();
  let rows=await query('pages','id,slug,title_en,title_zh,status,updated_at',{order:'updated_at',ascending:false,is:{deleted_at:null}});
  if(pageRouteFilter[route]) rows=rows.filter(row=>row.slug===pageRouteFilter[route]);
  document.querySelector('#content').innerHTML=head(titles[route],route==='pages'?'Manage safe, structured bilingual page content.':'Edit the existing page without touching source code.',`<button class="btn btn-primary" data-new>+ New page</button>`)+`<div class="toolbar"><input class="search" type="search" placeholder="Search pages…"></div><div class="records">${rows.length?rows.map(row=>`<article class="record-card" data-search="${esc(`${row.title_en} ${row.title_zh}`.toLowerCase())}"><div class="record-main"><b>${esc(state.lang==='zh'?row.title_zh:row.title_en)}</b><small>/${esc(row.slug)} · <span class="pill ${esc(row.status)}">${esc(row.status)}</span></small></div><div class="record-actions"><button class="btn" data-edit="${row.id}">Edit</button><a class="btn" href="${publicUrl}/${row.slug==='home'?'':`${row.slug}/`}" target="_blank">Preview</a></div></article>`).join(''):'<div class="empty">No CMS pages yet. Existing static pages remain unchanged.</div>'}</div>`;
  document.querySelector('[data-new]').onclick=()=>navigate('pages','new');
  document.querySelectorAll('[data-edit]').forEach(btn=>btn.onclick=()=>navigate(route,btn.dataset.edit));
  const search=document.querySelector('.search');search.oninput=()=>document.querySelectorAll('[data-search]').forEach(row=>row.hidden=!row.dataset.search.includes(search.value.toLowerCase()));
}

async function pageEditor() {
  loading(); const isNew=state.editId==='new';
  const row=isNew?{slug:'',title_en:'',title_zh:'',description_en:'',description_zh:'',status:'draft'}:(await query('pages','*',{eq:{id:state.editId}}))[0];
  if(!row){toast('Page not found',true);return navigate('pages');}
  const sections=isNew?[]:await query('page_sections','*',{eq:{page_id:row.id},order:'sort_order'});
  const render=()=>{
    const lang=state.lang;
    document.querySelector('#content').innerHTML=head(isNew?'New Page':`Edit ${row.title_en}`,'Draft changes are private until published.',`<button class="btn" data-back>← Back</button>`)+`<form id="page-form" class="editor"><div class="editor-main"><section class="panel">${languageTabs()}<div class="form-grid">${field('Page title',`title_${lang}`,row[`title_${lang}`]||'')}${area('Description',`description_${lang}`,row[`description_${lang}`]||'')}</div></section><section class="panel"><div class="toolbar"><h2>Page sections</h2><button class="btn" type="button" data-add-section>+ Add section</button></div><div class="section-list" id="section-list">${sections.length?sections.map(s=>`<div class="section-item" draggable="true" data-section="${s.id}"><div><b>${esc(s[`title_${lang}`]||s.section_key)}</b><small class="pill">${esc(s.section_type)}</small></div><button class="btn" type="button" data-section-edit="${s.id}">Edit</button></div>`).join(''):'<div class="empty">No structured sections yet.</div>'}</div></section></div><aside class="editor-side"><section class="panel"><h2>Publishing</h2>${selectField('Status','status',row.status,[['draft','Draft'],['published','Published'],['hidden','Hidden'],['archived','Archived']])}<button class="btn btn-primary" type="submit">${row.status==='published'?'Update published page':'Save page'}</button></section><section class="panel"><h2>URL</h2>${field('Slug','slug',row.slug,'text','pattern="[a-z0-9-]+" required')}<p class="message">Safe lowercase URL characters only.</p></section></aside></form>`;
    bindLanguageTabs(render);document.querySelector('[data-back]').onclick=()=>navigate(state.route);
    document.querySelector('#page-form').onsubmit=async e=>{e.preventDefault();const fd=new FormData(e.currentTarget);const payload={slug:slugify(fd.get('slug')),status:fd.get('status'),[`title_${lang}`]:fd.get(`title_${lang}`),[`description_${lang}`]:fd.get(`description_${lang}`)};if(!isNew){payload[`title_${lang==='en'?'zh':'en'}`]=row[`title_${lang==='en'?'zh':'en'}`];payload[`description_${lang==='en'?'zh':'en'}`]=row[`description_${lang==='en'?'zh':'en'}`];}else{payload.title_en=lang==='en'?fd.get('title_en'):'Untitled';payload.title_zh=lang==='zh'?fd.get('title_zh'):'未命名';}try{const saved=await saveRow('pages',payload,isNew?null:row.id);toast('Page saved');navigate('pages',saved.id);}catch(error){toast(error.message,true)}};
    document.querySelector('[data-add-section]').onclick=()=>openSectionModal(null,row,sections,render);
    document.querySelectorAll('[data-section-edit]').forEach(btn=>btn.onclick=()=>openSectionModal(sections.find(s=>s.id===btn.dataset.sectionEdit),row,sections,render));
    bindDragList(document.querySelector('#section-list'),async ids=>{for(let i=0;i<ids.length;i++)await supabase.from('page_sections').update({sort_order:i}).eq('id',ids[i]);toast('Section order saved')});
  };render();
}

function openSectionModal(section,page,sections,rerender) {
  if(!page.id){toast('Save the page before adding sections.',true);return;}
  const current=section||{section_key:`section-${sections.length+1}`,section_type:'text',title_en:'',title_zh:'',content_en:{text:''},content_zh:{text:''},is_visible:true};
  const modal=document.createElement('div');modal.className='modal-backdrop';modal.innerHTML=`<form class="modal"><div class="modal-head"><h2>${section?'Edit':'Add'} section</h2><button class="close" type="button">×</button></div>${field('Internal key','section_key',current.section_key)}${selectField('Preset layout','section_type',current.section_type,[['hero','Hero Banner'],['text','Text Block'],['image-text','Image + Text'],['full-image','Full-width Image'],['two-column','Two Columns'],['three-column','Three Columns'],['image-grid','Image Grid'],['project-cards','Project Cards'],['cta','Call To Action'],['spacer','Spacer'],['divider','Divider'],['gallery','Gallery']])}${field('English title','title_en',current.title_en)}${field('中文标题','title_zh',current.title_zh)}${area('English text','text_en',current.content_en?.text||'')}${area('中文内容','text_zh',current.content_zh?.text||'')}<label class="field"><span><input type="checkbox" name="is_visible" ${current.is_visible?'checked':''}> Visible</span></label><button class="btn btn-primary" type="submit">Save section</button>${section?'<button class="btn btn-danger" type="button" data-delete>Delete section</button>':''}</form>`;document.body.append(modal);
  modal.querySelector('.close').onclick=()=>modal.remove();modal.onclick=e=>{if(e.target===modal)modal.remove()};
  modal.querySelector('form').onsubmit=async e=>{e.preventDefault();const f=new FormData(e.currentTarget);const payload={page_id:page.id,section_key:slugify(f.get('section_key')),section_type:f.get('section_type'),title_en:f.get('title_en'),title_zh:f.get('title_zh'),content_en:{text:f.get('text_en')},content_zh:{text:f.get('text_zh')},is_visible:f.get('is_visible')==='on',sort_order:section?.sort_order??sections.length};const {data,error}=section?await supabase.from('page_sections').update(payload).eq('id',section.id).select().single():await supabase.from('page_sections').insert(payload).select().single();if(error)return toast(error.message,true);if(section)Object.assign(section,data);else sections.push(data);modal.remove();toast('Section saved');rerender()};
  if(section)modal.querySelector('[data-delete]').onclick=async()=>{if(!confirm('Delete this section? This action is recorded in version history.'))return;const{error}=await supabase.from('page_sections').delete().eq('id',section.id);if(error)return toast(error.message,true);sections.splice(sections.indexOf(section),1);modal.remove();rerender()};
}

function bindDragList(container,onSave){if(!container)return;let dragged;container.querySelectorAll('[draggable=true]').forEach(item=>{item.ondragstart=()=>{dragged=item;item.classList.add('dragging')};item.ondragend=async()=>{item.classList.remove('dragging');await onSave([...container.querySelectorAll('[data-section]')].map(x=>x.dataset.section))};item.ondragover=e=>{e.preventDefault();if(!dragged||dragged===item)return;const box=item.getBoundingClientRect();container.insertBefore(dragged,e.clientY<box.top+box.height/2?item:item.nextSibling)}})}

async function services() {
  if(state.editId)return serviceEditor();loading();
  const rows=await query('services','id,slug,title_en,title_zh,status,is_visible,project_url,service_categories(title_en,title_zh)',{order:'sort_order',is:{deleted_at:null}});
  document.querySelector('#content').innerHTML=head('Services','Manage the existing service taxonomy and project destinations.',`<button class="btn btn-primary" data-new>+ New service</button>`)+`<div class="records">${rows.map(row=>`<article class="record-card"><div class="record-main"><b>${esc(row.title_en)} / ${esc(row.title_zh)}</b><small>${esc(row.service_categories?.title_en||'')} · <span class="pill ${row.status}">${row.status}</span> · ${row.is_visible?'Visible':'Hidden'}</small></div><div class="record-actions"><button class="btn" data-edit="${row.id}">Edit</button><a class="btn" href="${esc(publicUrl+row.project_url)}" target="_blank">View</a></div></article>`).join('')}</div>`;
  document.querySelector('[data-new]').onclick=()=>navigate('services','new');document.querySelectorAll('[data-edit]').forEach(btn=>btn.onclick=()=>navigate('services',btn.dataset.edit));
}
async function serviceEditor(){loading();const isNew=state.editId==='new';const row=isNew?{slug:'',title_en:'',title_zh:'',description_en:'',description_zh:'',status:'draft',is_visible:true,sort_order:0,project_url:''}:(await query('services','*',{eq:{id:state.editId}}))[0];const cats=await query('service_categories','id,title_en,title_zh',{order:'sort_order'});const render=()=>{const l=state.lang;document.querySelector('#content').innerHTML=head(isNew?'New Service':row.title_en,'English and Chinese fields are managed together.',`<button class="btn" data-back>← Back</button>`)+`<form id="service-form" class="editor"><div class="editor-main"><section class="panel">${languageTabs()}${field('Service title',`title_${l}`,row[`title_${l}`]||'')}${area('Description',`description_${l}`,row[`description_${l}`]||'')}</section></div><aside class="editor-side"><section class="panel">${selectField('Category','category_id',row.category_id||cats[0]?.id,cats.map(c=>[c.id,c.title_en]))}${field('Slug','slug',row.slug)}${field('View Project URL','project_url',row.project_url)}${selectField('Status','status',row.status,[['draft','Draft'],['published','Published'],['hidden','Hidden'],['archived','Archived']])}${field('Order','sort_order',row.sort_order,'number')}<label class="field"><span><input name="is_visible" type="checkbox" ${row.is_visible?'checked':''}> Visible</span></label><button class="btn btn-primary" type="submit">Save service</button></section></aside></form>`;bindLanguageTabs(render);document.querySelector('[data-back]').onclick=()=>navigate('services');document.querySelector('#service-form').onsubmit=async e=>{e.preventDefault();const f=new FormData(e.currentTarget);const payload={category_id:f.get('category_id'),slug:slugify(f.get('slug')),project_url:f.get('project_url'),status:f.get('status'),sort_order:Number(f.get('sort_order')),is_visible:f.get('is_visible')==='on',[`title_${l}`]:f.get(`title_${l}`),[`description_${l}`]:f.get(`description_${l}`)};payload.title_en=l==='en'?payload.title_en:(row.title_en||'Untitled');payload.title_zh=l==='zh'?payload.title_zh:(row.title_zh||'未命名');payload.description_en=l==='en'?payload.description_en:row.description_en;payload.description_zh=l==='zh'?payload.description_zh:row.description_zh;try{const saved=await saveRow('services',payload,isNew?null:row.id);toast('Service saved');navigate('services',saved.id)}catch(error){toast(error.message,true)}}};render()}

async function projects(){if(state.editId)return projectEditor();loading();const rows=await query('projects','id,slug,title_en,title_zh,status,featured,updated_at,services(title_en)',{order:'updated_at',ascending:false,is:{deleted_at:null}});document.querySelector('#content').innerHTML=head('Work / Projects','Create bilingual showcases with the four approved sections.',`<button class="btn btn-primary" data-new>+ New project</button>`)+`<div class="records">${rows.length?rows.map(r=>`<article class="record-card"><div class="record-main"><b>${esc(r.title_en)} / ${esc(r.title_zh)}</b><small>${esc(r.services?.title_en||'Unassigned')} · <span class="pill ${r.status}">${r.status}</span>${r.featured?' · Featured':''}</small></div><div class="record-actions"><button class="btn" data-edit="${r.id}">Edit</button><a class="btn" href="${publicUrl}/projects/${esc(r.slug)}/" target="_blank">Preview</a></div></article>`).join(''):'<div class="empty">No database projects yet. Static portfolio content remains available.</div>'}</div>`;document.querySelector('[data-new]').onclick=()=>navigate('projects','new');document.querySelectorAll('[data-edit]').forEach(b=>b.onclick=()=>navigate('projects',b.dataset.edit))}

async function projectEditor(){loading();const isNew=state.editId==='new';const row=isNew?{slug:'',title_en:'',title_zh:'',short_description_en:'',short_description_zh:'',client_en:'',client_zh:'',industry_en:'',industry_zh:'',status:'draft',featured:false,year:new Date().getFullYear(),services_en:[],services_zh:[]}:(await query('projects','*',{eq:{id:state.editId}}))[0];if(!row)return navigate('projects');const servicesRows=await query('services','id,title_en',{is:{deleted_at:null},order:'sort_order'});let sections=isNew?[]:await query('project_sections','*',{eq:{project_id:row.id},order:'section_number'});const fixed=[['overview','Project Overview','项目概览'],['showcase','Project Showcase','项目展示'],['design-system','Design System','设计系统'],['deliverables','Final Deliverables','最终交付']];const render=()=>{const l=state.lang;document.querySelector('#content').innerHTML=head(isNew?'New Project':row.title_en,'Only Published projects appear on the public website.',`<button class="btn" data-back>← Back</button>`)+`<form id="project-form" class="editor"><div class="editor-main"><section class="panel">${languageTabs()}<div class="form-grid">${field('Project title',`title_${l}`,row[`title_${l}`])}${field('Client',`client_${l}`,row[`client_${l}`])}${field('Industry',`industry_${l}`,row[`industry_${l}`])}${area('Short description',`short_description_${l}`,row[`short_description_${l}`])}</div></section><section class="panel"><h2>Required project sections</h2><div class="section-list">${fixed.map((item,i)=>{const s=sections.find(x=>x.section_key===item[0]);return `<button class="section-item" type="button" data-project-section="${item[0]}"><div><b>${String(i+1).padStart(2,'0')}. ${esc(l==='zh'?item[2]:item[1])}</b><small>${s?'Configured':'Add content'}</small></div><span>→</span></button>`}).join('')}</div></section></div><aside class="editor-side"><section class="panel"><h2>Publishing</h2>${selectField('Service','service_id',row.service_id||servicesRows[0]?.id,servicesRows.map(s=>[s.id,s.title_en]))}${selectField('Status','status',row.status,[['draft','Draft'],['published','Published'],['hidden','Hidden'],['archived','Archived']])}${field('Publish date','published_at',row.published_at?.slice(0,16)||'','datetime-local')}<label class="field"><span><input name="featured" type="checkbox" ${row.featured?'checked':''}> Featured project</span></label><button class="btn btn-primary" type="submit">${row.status==='published'?'Update project':'Save draft'}</button></section><section class="panel"><h2>Project details</h2>${field('Slug','slug',row.slug)}${field('Year','year',row.year,'number')}</section></aside></form>`;bindLanguageTabs(render);document.querySelector('[data-back]').onclick=()=>navigate('projects');document.querySelector('#project-form').onsubmit=async e=>{e.preventDefault();const f=new FormData(e.currentTarget);const payload={service_id:f.get('service_id'),slug:slugify(f.get('slug')||f.get(`title_${l}`)),status:f.get('status'),featured:f.get('featured')==='on',published_at:f.get('published_at')?new Date(String(f.get('published_at'))).toISOString():null,year:Number(f.get('year')),[`title_${l}`]:f.get(`title_${l}`),[`client_${l}`]:f.get(`client_${l}`),[`industry_${l}`]:f.get(`industry_${l}`),[`short_description_${l}`]:f.get(`short_description_${l}`)};for(const key of ['title','client','industry','short_description'])payload[`${key}_${l==='en'?'zh':'en'}`]=row[`${key}_${l==='en'?'zh':'en'}`]|| (key==='title'?(l==='en'?'未命名':'Untitled'):'');try{const saved=await saveRow('projects',payload,isNew?null:row.id);if(isNew){for(let i=0;i<fixed.length;i++)await supabase.from('project_sections').insert({project_id:saved.id,section_key:fixed[i][0],section_number:i+1,title_en:fixed[i][1],title_zh:fixed[i][2]})}toast('Project saved');navigate('projects',saved.id)}catch(error){toast(error.message,true)}};document.querySelectorAll('[data-project-section]').forEach(b=>b.onclick=()=>openProjectSection(b.dataset.projectSection,row,sections,fixed,render))};render()}

function openProjectSection(key,project,sections,fixed,rerender){if(!project.id){toast('Save the project before editing its sections.',true);return}const index=fixed.findIndex(x=>x[0]===key),s=sections.find(x=>x.section_key===key)||{project_id:project.id,section_key:key,section_number:index+1,title_en:fixed[index][1],title_zh:fixed[index][2],content_en:{text:''},content_zh:{text:''},layout:'standard',is_visible:true};const modal=document.createElement('div');modal.className='modal-backdrop';modal.innerHTML=`<form class="modal"><div class="modal-head"><h2>${String(index+1).padStart(2,'0')}. ${esc(fixed[index][1])}</h2><button class="close" type="button">×</button></div>${field('English heading','title_en',s.title_en)}${area('English content','content_en',s.content_en?.text||'')}${field('中文标题','title_zh',s.title_zh)}${area('中文内容','content_zh',s.content_zh?.text||'')}${selectField('Layout','layout',s.layout,[['standard','Standard'],['full-width','Full width'],['two-column','Two columns'],['grid','Grid']])}<label class="field"><span><input name="is_visible" type="checkbox" ${s.is_visible?'checked':''}> Visible</span></label><button class="btn btn-primary">Save section</button></form>`;document.body.append(modal);modal.querySelector('.close').onclick=()=>modal.remove();modal.querySelector('form').onsubmit=async e=>{e.preventDefault();const f=new FormData(e.currentTarget),payload={...s,title_en:f.get('title_en'),title_zh:f.get('title_zh'),content_en:{text:f.get('content_en')},content_zh:{text:f.get('content_zh')},layout:f.get('layout'),is_visible:f.get('is_visible')==='on'};delete payload.id;delete payload.created_at;delete payload.updated_at;const{data,error}=await supabase.from('project_sections').upsert(payload,{onConflict:'project_id,section_key'}).select().single();if(error)return toast(error.message,true);const old=sections.findIndex(x=>x.section_key===key);old>=0?sections[old]=data:sections.push(data);modal.remove();toast('Project section saved');rerender()}}

async function media(){loading();const rows=await query('media','*',{order:'created_at',ascending:false,is:{deleted_at:null}});document.querySelector('#content').innerHTML=head('Media Library','Optimized, reusable website images with bilingual alt text.')+`<label class="dropzone"><b>Upload images</b><p>JPG, PNG, WebP or AVIF · maximum 10 MB each · converted to WebP where supported</p><input id="media-upload" type="file" multiple accept="image/jpeg,image/png,image/webp,image/avif"></label><div class="media-grid">${rows.length?rows.map(m=>`<article class="media-card"><img src="${esc(m.public_url)}" alt="${esc(m.alt_en)}" loading="lazy"><div><b>${esc(m.title_en||m.original_name)}</b><small>${Math.round(m.size_bytes/1024)} KB · ${m.width||'?'}×${m.height||'?'}</small><button class="link-button" data-media-delete="${m.id}">Delete</button></div></article>`).join(''):'<div class="empty">No uploaded media yet.</div>'}</div>`;document.querySelector('#media-upload').onchange=e=>uploadMedia([...e.target.files]);document.querySelectorAll('[data-media-delete]').forEach(b=>b.onclick=()=>deleteMedia(rows.find(x=>x.id===b.dataset.mediaDelete)))}
async function optimizeImage(file){if(file.type==='image/avif'||file.type==='image/webp')return{blob:file,width:0,height:0};const bitmap=await createImageBitmap(file);const scale=Math.min(1,2560/Math.max(bitmap.width,bitmap.height));const canvas=document.createElement('canvas');canvas.width=Math.round(bitmap.width*scale);canvas.height=Math.round(bitmap.height*scale);canvas.getContext('2d').drawImage(bitmap,0,0,canvas.width,canvas.height);const blob=await new Promise(resolve=>canvas.toBlob(resolve,'image/webp',.86));bitmap.close();return{blob:blob||file,width:canvas.width,height:canvas.height}}
async function uploadMedia(files){const allowed=new Set(['image/jpeg','image/png','image/webp','image/avif']);for(const file of files){if(!allowed.has(file.type)||file.size>10485760){toast(`${file.name}: unsupported type or larger than 10 MB`,true);continue}try{toast(`Optimizing ${file.name}…`);const output=await optimizeImage(file),extension=output.blob.type==='image/webp'?'webp':file.name.split('.').pop().toLowerCase(),name=`${state.profile.user_id}/${Date.now()}-${crypto.randomUUID()}.${extension}`;const{error}=await supabase.storage.from('cms-media').upload(name,output.blob,{contentType:output.blob.type,cacheControl:'31536000',upsert:false});if(error)throw error;const{data:url}=supabase.storage.from('cms-media').getPublicUrl(name);const{error:dbError}=await supabase.from('media').insert({object_path:name,public_url:url.publicUrl,original_name:file.name,mime_type:output.blob.type,size_bytes:output.blob.size,width:output.width||null,height:output.height||null,uploaded_by:state.profile.user_id});if(dbError){await supabase.storage.from('cms-media').remove([name]);throw dbError}toast(`${file.name} uploaded`)}catch(error){toast(error.message,true)}}media()}
async function deleteMedia(item){const [servicesUse,coverUse,shareUse,projectUse]=await Promise.all([query('services','id',{eq:{cover_media_id:item.id}}),query('projects','id',{eq:{cover_media_id:item.id}}),query('projects','id',{eq:{share_media_id:item.id}}),query('project_media','project_id',{eq:{media_id:item.id}})]);const count=servicesUse.length+coverUse.length+shareUse.length+projectUse.length;if(count)return toast(`This image is used in ${count} place(s) and cannot be deleted.`,true);if(!confirm('Delete this unused image?'))return;const{error}=await supabase.storage.from('cms-media').remove([item.object_path]);if(error)return toast(error.message,true);await supabase.from('media').update({deleted_at:new Date().toISOString()}).eq('id',item.id);toast('Image moved to trash');media()}

async function simpleSettings(route){loading();const table=route==='theme'?'theme_settings':route==='seo'?'seo_settings':route==='navigation'?'navigation_items':'site_settings';if(route==='navigation')return navigation();if(route==='seo')return seo();const rows=await query(table,'*');const row=rows[0]||{};if(route==='theme')return themeEditor(row);return settingsEditor(row,route)}
function themeEditor(row){const colors=row.colors||{};const fonts=row.fonts||{};const colorNames=['primary','secondary','accent','background','surface','text','muted','button','link','border','dark'];document.querySelector('#content').innerHTML=head('Theme & Design','Safe design tokens update the whole site consistently.')+`<form id="theme-form" class="grid-2"><section class="panel"><h2>Colors</h2><div class="color-grid">${colorNames.map(name=>`<label class="field color-field"><input type="color" name="${name}" value="${esc(colors[name]||'#000000')}"><span>${esc(name)}</span></label>`).join('')}</div></section><section class="panel"><h2>Typography</h2>${['heading','body','button','navigation'].map(name=>selectField(name[0].toUpperCase()+name.slice(1),name,fonts[name]||'Inter',['Inter','Poppins','Montserrat','Playfair Display','Manrope','DM Sans','Lato','Roboto'].map(v=>[v,v]))).join('')}<div class="preview-strip" id="theme-preview"><h3>INfinity Design Studio</h3><p>Live token preview for headings, text, borders and buttons.</p><button class="btn">Preview button</button></div><button class="btn btn-primary" type="submit">Save theme</button></section></form>`;const form=document.querySelector('#theme-form'),preview=document.querySelector('#theme-preview');const update=()=>{preview.style.setProperty('--preview-bg',form.background.value);preview.style.setProperty('--preview-text',form.text.value);preview.style.setProperty('--preview-border',form.border.value);preview.style.setProperty('--preview-accent',form.accent.value)};form.querySelectorAll('input[type=color]').forEach(i=>i.oninput=update);update();form.onsubmit=async e=>{e.preventDefault();const f=new FormData(form),newColors={},newFonts={};colorNames.forEach(k=>newColors[k]=f.get(k));['heading','body','button','navigation'].forEach(k=>newFonts[k]=f.get(k));const{error}=await supabase.from('theme_settings').upsert({id:true,colors:newColors,fonts:newFonts,updated_by:state.profile.user_id});toast(error?error.message:'Theme saved',Boolean(error))}}
function settingsEditor(row,route){const footer=route==='footer';document.querySelector('#content').innerHTML=head(footer?'Footer':'Website Settings',footer?'Edit bilingual footer and legal text.':'Manage studio identity, contact details and site status.')+`<form id="settings-form" class="editor"><div class="editor-main"><section class="panel">${footer?`${field('Copyright (English)','copyright_en',row.copyright_en)}${field('版权文字（中文）','copyright_zh',row.copyright_zh)}${area('Footer English JSON','footer_en',JSON.stringify(row.footer_en||{},null,2))}${area('Footer Chinese JSON','footer_zh',JSON.stringify(row.footer_zh||{},null,2))}`:`${field('Studio name','studio_name',row.studio_name)}${field('Contact email','contact_email',row.contact_email,'email')}${field('WhatsApp URL','whatsapp_url',row.whatsapp_url)}${area('Social links JSON','social_links',JSON.stringify(row.social_links||{},null,2))}`}</section></div><aside class="editor-side"><section class="panel">${selectField('Default language','default_language',row.default_language||'en',[['en','English'],['zh','中文']])}${selectField('Website status','website_status',row.website_status||'live',[['live','Live'],['maintenance','Maintenance']])}<button class="btn btn-primary">Save settings</button></section>${!footer?'<div class="danger-note">Maintenance mode affects public visitors. Preview remains available to signed-in administrators.</div>':''}</aside></form>`;document.querySelector('#settings-form').onsubmit=async e=>{e.preventDefault();const f=new FormData(e.currentTarget);try{const payload={id:true,default_language:f.get('default_language'),website_status:f.get('website_status'),updated_by:state.profile.user_id};if(footer){payload.copyright_en=f.get('copyright_en');payload.copyright_zh=f.get('copyright_zh');payload.footer_en=JSON.parse(f.get('footer_en')||'{}');payload.footer_zh=JSON.parse(f.get('footer_zh')||'{}')}else{payload.studio_name=f.get('studio_name');payload.contact_email=f.get('contact_email');payload.whatsapp_url=f.get('whatsapp_url');payload.social_links=JSON.parse(f.get('social_links')||'{}')}const{error}=await supabase.from('site_settings').upsert(payload);if(error)throw error;toast('Settings saved')}catch(error){toast(`Check JSON and fields: ${error.message}`,true)}}}
async function navigation(){const rows=await query('navigation_items','*',{order:'sort_order'});document.querySelector('#content').innerHTML=head('Navigation','Safe bilingual links for desktop and mobile.',`<button class="btn btn-primary" data-new>+ Add item</button>`)+`<div class="records">${rows.map(r=>`<article class="record-card"><div class="record-main"><b>${esc(r.label_en)} / ${esc(r.label_zh)}</b><small>${esc(r.url)} · ${r.is_visible?'Visible':'Hidden'}</small></div><button class="btn" data-edit="${r.id}">Edit</button></article>`).join('')||'<div class="empty">No database navigation yet. Static navigation remains active.</div>'}</div>`;const open=item=>{const r=item||{label_en:'',label_zh:'',url:'/',target:'_self',is_visible:true,mobile_visible:true,sort_order:rows.length};const modal=document.createElement('div');modal.className='modal-backdrop';modal.innerHTML=`<form class="modal"><div class="modal-head"><h2>${item?'Edit':'Add'} navigation item</h2><button class="close" type="button">×</button></div>${field('English label','label_en',r.label_en)}${field('中文名称','label_zh',r.label_zh)}${field('Safe URL','url',r.url)}${field('Order','sort_order',r.sort_order,'number')}<label class="field"><span><input name="is_visible" type="checkbox" ${r.is_visible?'checked':''}> Visible</span></label><label class="field"><span><input name="mobile_visible" type="checkbox" ${r.mobile_visible?'checked':''}> Mobile visible</span></label><button class="btn btn-primary">Save item</button></form>`;document.body.append(modal);modal.querySelector('.close').onclick=()=>modal.remove();modal.querySelector('form').onsubmit=async e=>{e.preventDefault();const f=new FormData(e.currentTarget),url=String(f.get('url'));if(!/^(\/|#|https:\/\/)/.test(url))return toast('URL must start with /, # or https://',true);const payload={label_en:f.get('label_en'),label_zh:f.get('label_zh'),url,target:'_self',sort_order:Number(f.get('sort_order')),is_visible:f.get('is_visible')==='on',mobile_visible:f.get('mobile_visible')==='on'};const req=item?supabase.from('navigation_items').update(payload).eq('id',item.id):supabase.from('navigation_items').insert(payload);const{error}=await req;if(error)return toast(error.message,true);modal.remove();toast('Navigation saved');navigation()}};document.querySelector('[data-new]').onclick=()=>open();document.querySelectorAll('[data-edit]').forEach(b=>b.onclick=()=>open(rows.find(r=>r.id===b.dataset.edit)))}
async function seo(){const rows=await query('seo_settings','*',{order:'page_key'});document.querySelector('#content').innerHTML=head('SEO','Manage metadata without exposing dangerous global indexing controls.',`<button class="btn btn-primary" data-new>+ Add page SEO</button>`)+`<div class="records">${rows.map(r=>`<article class="record-card"><div class="record-main"><b>${esc(r.page_key)}</b><small>${esc(r.title_en)} · ${r.robots_index?'Index':'No index'}</small></div><button class="btn" data-edit="${r.id}">Edit</button></article>`).join('')||'<div class="empty">No database SEO overrides yet. Existing metadata remains active.</div>'}</div><div class="danger-note" style="margin-top:18px">Disabling indexing requires an explicit confirmation. Sitemap and robots files remain in source control until dynamic generation is enabled.</div>`;const open=item=>{const r=item||{page_key:'',title_en:'',title_zh:'',description_en:'',description_zh:'',canonical_url:'',robots_index:true,robots_follow:true};const modal=document.createElement('div');modal.className='modal-backdrop';modal.innerHTML=`<form class="modal"><div class="modal-head"><h2>Page SEO</h2><button class="close" type="button">×</button></div>${field('Page key','page_key',r.page_key)}${field('English title','title_en',r.title_en)}${area('English description','description_en',r.description_en)}${field('中文标题','title_zh',r.title_zh)}${area('中文描述','description_zh',r.description_zh)}${field('Canonical URL','canonical_url',r.canonical_url,'url')}<label class="field"><span><input name="robots_index" type="checkbox" ${r.robots_index?'checked':''}> Allow search indexing</span></label><button class="btn btn-primary">Save SEO</button></form>`;document.body.append(modal);modal.querySelector('.close').onclick=()=>modal.remove();modal.querySelector('form').onsubmit=async e=>{e.preventDefault();const f=new FormData(e.currentTarget),index=f.get('robots_index')==='on';if(!index&&!confirm('This can remove a page from search results. Save no-index setting?'))return;const payload={page_key:slugify(f.get('page_key')),title_en:f.get('title_en'),title_zh:f.get('title_zh'),description_en:f.get('description_en'),description_zh:f.get('description_zh'),canonical_url:f.get('canonical_url'),robots_index:index,robots_follow:true,updated_by:state.profile.user_id};const req=item?supabase.from('seo_settings').update(payload).eq('id',item.id):supabase.from('seo_settings').insert(payload);const{error}=await req;if(error)return toast(error.message,true);modal.remove();seo()}};document.querySelector('[data-new]').onclick=()=>open();document.querySelectorAll('[data-edit]').forEach(b=>b.onclick=()=>open(rows.find(r=>r.id===b.dataset.edit)))}

async function adminRequest(action,payload={}){const{data,error}=await supabase.functions.invoke('admin-users',{body:{action,...payload}});if(error||data?.error)throw new Error(data?.error||error.message);return data}
async function users(){
  loading();
  if(state.profile.role!=='owner'){document.querySelector('#content').innerHTML=head('User Management','Owner access is required.')+'<div class="empty">Editors cannot access administrator records or management actions.</div>';return}
  const rows=(await adminRequest('list')).users||[];
  document.querySelector('#content').innerHTML=head('User Management','Owner-only account controls, security status and activity history.',`<button class="btn btn-primary" data-create-admin>+ Create administrator</button>`)+`<div class="records">${rows.map(r=>{const protectedOwner=r.username==='owner';return `<article class="record-card"><div class="record-main"><b>${esc(r.display_name)} <span class="pill">${esc(r.role)}</span> <span class="pill ${r.is_active?'published':'archived'}">${r.is_active?'Active':'Disabled'}</span></b><small>Username: <strong>${esc(r.username)}</strong> · Email: <strong>${esc(r.email||'Unavailable')}</strong></small><small>Last login: ${r.last_sign_in_at?new Date(r.last_sign_in_at).toLocaleString():'Never'} · Last IP: ${esc(r.last_ip||'Not recorded')}</small><details><summary>Activity history (${r.history?.length||0})</summary>${(r.history||[]).map(log=>`<div class="log"><time>${new Date(log.created_at).toLocaleString()}</time><span>${esc(log.action)}</span><b>${esc(log.entity_table||'authentication')}</b></div>`).join('')||'<div class="empty">No activity recorded.</div>'}</details></div><div class="record-actions"><button class="btn" data-edit-admin="${r.user_id}">Edit</button><button class="btn" data-reset-admin="${r.user_id}">Reset password</button>${protectedOwner?'':`<button class="btn" data-toggle-admin="${r.user_id}">${r.is_active?'Disable':'Enable'}</button><button class="btn btn-danger" data-delete-admin="${r.user_id}">Delete</button>`}</div></article>`}).join('')}</div>`;
  const byId=id=>rows.find(row=>row.user_id===id);
  document.querySelector('[data-create-admin]').onclick=()=>openCreateAdmin();
  document.querySelectorAll('[data-edit-admin]').forEach(button=>button.onclick=()=>openEditAdmin(byId(button.dataset.editAdmin)));
  document.querySelectorAll('[data-reset-admin]').forEach(button=>button.onclick=()=>openAdminPassword(byId(button.dataset.resetAdmin)));
  document.querySelectorAll('[data-toggle-admin]').forEach(button=>button.onclick=async()=>{const row=byId(button.dataset.toggleAdmin);if(row.is_active&&!confirm(`Disable ${row.display_name}? Their CMS access will stop immediately.`))return;try{await adminRequest('update',{userId:row.user_id,displayName:row.display_name,email:row.email,role:row.role,isActive:!row.is_active});toast(row.is_active?'Administrator disabled':'Administrator enabled');users()}catch(error){toast(error.message,true)}});
  document.querySelectorAll('[data-delete-admin]').forEach(button=>button.onclick=async()=>{const row=byId(button.dataset.deleteAdmin);if(!confirm(`Permanently delete ${row.display_name}? This cannot be undone.`))return;try{await adminRequest('delete',{userId:row.user_id});toast('Administrator deleted');users()}catch(error){toast(error.message,true)}});
}
function openCreateAdmin(){const modal=document.createElement('div');modal.className='modal-backdrop';modal.innerHTML=`<form class="modal"><div class="modal-head"><h2>Create administrator</h2><button class="close" type="button">×</button></div>${field('Username','username','','text','pattern="[a-z0-9-]{3,32}" required')}${field('Display name','displayName','Editor','','required')}${field('Login email','email','','email','required')}${selectField('Role','role','editor',[['editor','Editor'],['owner','Owner']])}${field('Temporary password','password','','password','minlength="12" autocomplete="new-password" required')}${field('Confirm password','confirm','','password','minlength="12" autocomplete="new-password" required')}<button class="btn btn-primary">Create account</button></form>`;document.body.append(modal);modal.querySelector('.close').onclick=()=>modal.remove();modal.querySelector('form').onsubmit=async e=>{e.preventDefault();const f=new FormData(e.currentTarget);if(f.get('password')!==f.get('confirm'))return toast('Passwords do not match.',true);try{await adminRequest('create',{username:f.get('username'),displayName:f.get('displayName'),email:f.get('email'),role:f.get('role'),password:f.get('password')});modal.remove();toast('Administrator created');users()}catch(error){toast(error.message,true)}}}
function openEditAdmin(row){const protectedOwner=row.username==='owner';const modal=document.createElement('div');modal.className='modal-backdrop';modal.innerHTML=`<form class="modal"><div class="modal-head"><h2>Edit ${esc(row.display_name)}</h2><button class="close" type="button">×</button></div>${field('Display name','displayName',row.display_name,'text','required')}${field('Login email','email',row.email,'email','required')}${protectedOwner?'<div class="danger-note">The Owner role and active status are permanently protected.</div>':selectField('Role','role',row.role,[['editor','Editor'],['owner','Owner']])}<button class="btn btn-primary">Save administrator</button></form>`;document.body.append(modal);modal.querySelector('.close').onclick=()=>modal.remove();modal.querySelector('form').onsubmit=async e=>{e.preventDefault();const f=new FormData(e.currentTarget);try{await adminRequest('update',{userId:row.user_id,displayName:f.get('displayName'),email:f.get('email'),role:protectedOwner?'owner':f.get('role'),isActive:protectedOwner?true:row.is_active});modal.remove();toast('Administrator updated');users()}catch(error){toast(error.message,true)}}}
function openAdminPassword(row){const modal=document.createElement('div');modal.className='modal-backdrop';modal.innerHTML=`<form class="modal"><div class="modal-head"><h2>Reset ${esc(row.display_name)} password</h2><button class="close" type="button">×</button></div><p class="message">No email verification is required. The new password is never displayed or stored by the CMS.</p>${field('New password','password','','password','minlength="12" autocomplete="new-password" required')}${field('Confirm password','confirm','','password','minlength="12" autocomplete="new-password" required')}<button class="btn btn-primary">Reset password</button></form>`;document.body.append(modal);modal.querySelector('.close').onclick=()=>modal.remove();modal.querySelector('form').onsubmit=async e=>{e.preventDefault();const f=new FormData(e.currentTarget);if(f.get('password')!==f.get('confirm'))return toast('Passwords do not match.',true);try{await adminRequest('reset-password',{userId:row.user_id,password:f.get('password')});modal.remove();toast('Password reset complete')}catch(error){toast(error.message,true)}}}
async function activity(){if(state.profile.role!=='owner'){document.querySelector('#content').innerHTML=head('Activity Log','Owner access is required.')+'<div class="empty">Editors cannot view administrator activity logs.</div>';return}loading();const [rows,versions]=await Promise.all([query('activity_logs','id,action,entity_table,entity_id,metadata,created_at,admin_users(display_name)',{order:'created_at',ascending:false}),query('content_versions','id,entity_table,entity_id,operation,before_data,after_data,created_at,admin_users(display_name)',{order:'created_at',ascending:false})]);document.querySelector('#content').innerHTML=head('Activity Log','Traceable changes, publishing activity and recoverable versions.')+`<div class="grid-2"><section class="panel"><h2>Recent activity</h2>${rows.slice(0,100).map(r=>`<div class="log"><time>${new Date(r.created_at).toLocaleString()}</time><span>${esc(r.admin_users?.display_name||'System')}</span><b>${esc(r.action)} · ${esc(r.entity_table||'authentication')}</b></div>`).join('')||'<div class="empty">No activity recorded yet.</div>'}</section><section class="panel"><h2>Previous versions</h2>${versions.slice(0,50).map(v=>`<div class="record-card"><div class="record-main"><b>${esc(v.entity_table)} · ${esc(v.operation)}</b><small>${new Date(v.created_at).toLocaleString()}</small></div>${v.before_data&&['pages','projects'].includes(v.entity_table)?`<button class="btn" data-restore="${v.id}">Restore</button>`:''}</div>`).join('')||'<div class="empty">No versions yet.</div>'}</section></div>`;document.querySelectorAll('[data-restore]').forEach(button=>button.onclick=async()=>{const version=versions.find(v=>String(v.id)===button.dataset.restore);if(!version||!confirm('Restore this previous version? The current version will also be preserved.'))return;const payload={...version.before_data};delete payload.id;delete payload.created_at;delete payload.updated_at;const{error}=await supabase.from(version.entity_table).update(payload).eq('id',version.entity_id);if(error)return toast(error.message,true);toast('Previous version restored');activity()})}
function languages(){document.querySelector('#content').innerHTML=head('Languages','English and Simplified Chinese are first-class content fields.')+`<div class="grid-2"><section class="panel"><h2>English</h2><p>Primary locale: <b>en</b></p><p class="message">All Pages, Services, Projects, Navigation, Footer and SEO records include dedicated English fields.</p></section><section class="panel"><h2>中文（简体）</h2><p>语言代码：<b>zh-CN</b></p><p class="message">所有页面、服务、项目、导航、页脚和 SEO 内容均拥有独立中文字段。</p></section></div>`}

async function renderRoute(){parseRoute();document.querySelectorAll('[data-route]').forEach(a=>a.classList.toggle('active',a.dataset.route===state.route));const label=document.querySelector('.topbar .eyebrow');if(label)label.textContent=titles[state.route];try{if(state.route==='dashboard')await dashboard();else if(['pages','home','about'].includes(state.route))await pages(state.route);else if(state.route==='services')await services();else if(state.route==='projects')await projects();else if(state.route==='media')await media();else if(['theme','footer','settings','navigation','seo'].includes(state.route))await simpleSettings(state.route);else if(state.route==='users')await users();else if(state.route==='activity')await activity();else if(state.route==='languages')languages()}catch(error){console.error(error);document.querySelector('#content').innerHTML=head('Unable to load','The CMS received a database error.')+`<div class="danger-note">${esc(error.message)}</div>`}}

async function start(){if(!configured)return setupView();const {data}=await supabase.auth.getSession();state.session=data.session;if(!state.session)return authView();if(!await loadProfile())return authView();parseRoute();shell()}
window.addEventListener('hashchange',()=>{if(state.session)renderRoute()});
if(supabase)supabase.auth.onAuthStateChange(async(event,session)=>{state.session=session;if(event==='SIGNED_OUT'){state.profile=null;authView()}else if(event==='SIGNED_IN'&&!state.profile){if(await loadProfile()){parseRoute();shell()}}});
start();

let lastActivity=Date.now();['pointerdown','keydown','scroll'].forEach(event=>window.addEventListener(event,()=>{lastActivity=Date.now()},{passive:true}));
setInterval(()=>{if(state.session&&Date.now()-lastActivity>30*60*1000)supabase?.auth.signOut()},60*1000);
